#!/bin/bash\n\n# GBSB Digital Gurukul - Setup Script\n# This script sets up the development environment\n\necho \"========================================\"\necho \"GBSB Digital Gurukul - Setup Script\"\necho \"========================================\"\n\n# Check if Docker is installed\nif ! command -v docker &> /dev/null; then\n    echo \"Docker not found. Installing Docker...\"\n    curl -fsSL https://get.docker.com -o get-docker.sh\n    sh get-docker.sh\nfi\n\n# Check if Docker Compose is installed\nif ! command -v docker-compose &> /dev/null; then\n    echo \"Docker Compose not found. Installing...\"\n    sudo apt-get update\n    sudo apt-get install -y docker-compose\nfi\n\necho \"Starting services...\"\ndocker-compose up -d\n\necho \"\"\necho \"========================================\"\necho \"Setup Complete!\"\necho \"========================================\"\necho \"\"\necho \"Services running at:\"\necho \"- API: http://localhost:8000\"\necho \"- API Docs: http://localhost:8000/docs\"\necho \"- Jitsi: http://localhost:8080\"\necho \"- PostgreSQL: localhost:5432\"\necho \"\"\necho \"Next steps:\"\necho \"1. Setup Ollama models:\"\necho \"   docker exec gbsb_ollama ollama pull mistral\"\necho \"2. Access API at http://localhost:8000/docs\"\necho \"3. Create your first account!\"\necho \"\"\n"